using System.ComponentModel.DataAnnotations;using System.ComponentModel.DataAnnotations.Schema;namespace CollegeManagementSystem.Data.Entities;[Table("Instructors")]public class Instructor{    [Key] public int Id { get; set; }    [Required] [MaxLength(50)] public string FirstName { get; set; } = string.Empty;    [Required] [MaxLength(50)] public string LastName { get; set; } = string.Empty;    [Required]    [EmailAddress]    [MaxLength(255)]    public string Email { get; set; } = string.Empty;    [Required] public DateTime HireDate { get; set; }    public List<ModuleInstructor> ModuleInstructors { get; set; } = [];}